export const nextGeneration = (cells: Cell[]): Cell[] => {
  const aliveKeys = new Set(cells.map(([x, y]) => cellKey(x, y)));

  const countLiveNeighbors = (x: number, y: number): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => aliveKeys.has(cellKey(x + dx, y + dy))).length;

  const survivors = cells.filter(([x, y]) => {
    const neighborCount = countLiveNeighbors(x, y);
    return neighborCount === 2 || neighborCount === 3;
  });

  const candidateBirths = new Map<string, Cell>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const k = cellKey(nx, ny);
      if (aliveKeys.has(k)) continue;
      candidateBirths.set(k, [nx, ny]);
    }
  }

  const births: Cell[] = [];
  for (const [, cell] of candidateBirths) {
    if (countLiveNeighbors(cell[0], cell[1]) === 3) births.push(cell);
  }

  return [...survivors, ...births];
};

