export const nextGeneration = (cells: Cell[]): Cell[] => {
  const aliveKeys = new Set(cells.map(([x, y]) => cellKey(x, y)));

  const neighborsOf = ([x, y]: Cell): Cell[] =>
    NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

  const countLiveNeighbors = (cell: Cell): number =>
    neighborsOf(cell).filter(([nx, ny]) => aliveKeys.has(cellKey(nx, ny))).length;

  const isAlive = (cell: Cell): boolean => aliveKeys.has(cellKey(cell[0], cell[1]));

  const survives = (cell: Cell): boolean => {
    const count = countLiveNeighbors(cell);
    return count === 2 || count === 3;
  };

  const isBorn = (cell: Cell): boolean =>
    !isAlive(cell) && countLiveNeighbors(cell) === 3;

  const candidates = new Map<string, Cell>();
  for (const cell of cells) {
    candidates.set(cellKey(cell[0], cell[1]), cell);
    for (const neighbor of neighborsOf(cell)) {
      candidates.set(cellKey(neighbor[0], neighbor[1]), neighbor);
    }
  }

  return [...candidates.values()].filter(
    (cell) => (isAlive(cell) ? survives(cell) : isBorn(cell)),
  );
};

