export const nextGeneration = (cells: Cell[]): Cell[] => {
  const aliveKeys = new Set(cells.map(([x, y]) => cellKey(x, y)));

  const neighborsOf = ([x, y]: Cell): Cell[] =>
    NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

  const isAlive = (cell: Cell): boolean => aliveKeys.has(cellKey(cell[0], cell[1]));

  const countLiveNeighbors = (cell: Cell): number =>
    neighborsOf(cell).filter(isAlive).length;

  const livesNextGeneration = (cell: Cell): boolean => {
    const count = countLiveNeighbors(cell);
    return count === 3 || (count === 2 && isAlive(cell));
  };

  const candidates = new Map<string, Cell>();
  for (const cell of cells) {
    for (const candidate of [cell, ...neighborsOf(cell)]) {
      candidates.set(cellKey(candidate[0], candidate[1]), candidate);
    }
  }

  return [...candidates.values()].filter(livesNextGeneration);
};
